\begin{proof}
	Fix $j\in\{1,2,\ldots,r\}$. Since $n=rq+1$, we have \begin{align}\label{eq 1.1.6}
		\frac{(jq)r}{n}=\frac{j(n-1)}{n}<j
	\end{align}
\begin{align}\label{eq 1.1.7}
	\frac{(jq)r}{n}-(j-1)=\frac{jqr-jn+n}{n}=\frac{n-j}{n}>0
\end{align}
From \cref{eq 1.1.6} and \cref{eq 1.1.7}, we have 
\begin{align*}
	j-1<\frac{(jq)r}{n}<j.
\end{align*}
Therefore, we have $\lfloor\frac{(jq)r}{n}\rfloor=j-1$. Now the proof follows from \cite[Lemma 5.8]{GKgit}.
\end{proof}

