\begin{proof}
 	Let $w(\omega_{r})=\omega_{r}-\sum_{k=1}^{n-1}a_{i}\alpha_{i}$, where $a_{i}\in\mathbb{Z}_{\geq 0}$. Note that $a_{i}$ is the number of times the simple reflection $s_{i}$ appears in a reduced expression of $w$ (see \cite[Corollary 1.4]{sskannan}). \\
 	Then we have $\langle w(n\omega_{r}),\lambda_{iq}\rangle=\langle n\omega_{r},\lambda_{iq}\rangle-na_{iq}$.
 	From the description of $\omega_{r}$ in \cite[p.69]{Hum1}, we have
 	\begin{align*}
 		\langle n\omega_{r},\lambda_{iq}\rangle&=\begin{dcases}
 		r(n-iq)&\text{\ if $r\leq iq$}\\
 		iq(n-r)&\text{\ if $iq<r$}
 		\end{dcases}
 	\end{align*}
 	{\it Case 1}: Let $r\leq iq$. In this case $a_{iq}=r-i+1$. Therefore, we have
 	\begin{align*}
 		\langle w(n\omega_{r}),\lambda_{iq}\rangle=r(n-iq)-n(r-i+1)
 		&=-irq+in-n\\
 	%	&=i(n-rq)-n\\
 		&=i-n\text{\ (using $n=rq+1$)}\\
 		&=-(n-i).
 	\end{align*}
 	{\it Case 2}: Let $r>iq$. In this case $a_{iq}=iq-i+1$. Therefore, we have
 	\begin{align*}
 		\langle w(n\omega_{r}),\lambda_{iq}\rangle=iq(n-r)-n(iq-i+1)
 		&=-irq+in-n\\
 		&=i-n(\ \text{using $n=rq+1$})\\
 		&=-(n-i).
 	\end{align*}
 \end{proof}

