\begin{proof}
	Recall that $m(i_{j},j)$ be the largest non negative integer such that $e^{m(i_{j},j)}(i_{j},j)\geq 0$. We prove that $e^{m(i_{j},j)}(i_{j},j)=0$. Assume on the contrary that $e^{m(i_{j},j)}(i_{j},j)\geq 1$. Then, we have \begin{align}\label{eq 1.1}
	e^{m(i_{j},j)+1}(i_{j},j)=d(i_{e^{m(i_{j},j)}(i_{j},j)},e^{m(i_{j},j)}(i_{j},j))-1.
\end{align}
Since $e^{m(i_{j},j)}(i_{j},j)\geq 1$, we have $d(i_{e^{m(i_{j},j)}(i_{j},j)},e^{m(i_{j},j)}(i_{j},j))\geq 1$. Thus from \cref{eq 1.1}, we have $e^{m(i_{j},j)+1}(i_{j},j)\geq 1-1=0$. This contradicts the maximality of $m(i_{j},j)$. Hence, $e^{m(i_{j},j)}(i_{j},j)=0$.
\end{proof}

