\begin{proof} Step 1: We prove that $\langle\gamma_{j},\lambda_{lq}\rangle=0$ for every integer $l$ such that $j+1\leq l\leq r$.

	Let $j+1\leq l\leq r$.
	Since $e^{0}(i_{j},j)=j$ and $e^{k}(i_{j},j)<e^{0}(i_{j},j)$ for all $1\leq k\leq m(i_{j},j)-1$, we have $l>e^{k}(i_{j},j)$ for $0\leq k\leq m(i_{j},j)-1$. Therefore, from \cref{claim 1}, we have  $\langle\beta_{i_{e^{k}(i_{j},j)},e^{k}(i_{j},j)},\lambda_{lq}\rangle=0$ for $0\leq k\leq m(i_{j},j)-1$. Hence, from \cref{eq 1.14}, we have $\langle\gamma_{j},\lambda_{lq}\rangle=0$.\\
	Step 2: We prove that $\langle\gamma_{j},\lambda_{lq}\rangle=1$, for every integer $l$ such that $1\leq l\leq j$.

	Let $1\leq l\leq j$. Since $e^{0}(i_{j},j)=j$, using \cref{lemma 2.1} and \cref{e^{m}=0}, we have 
	\begin{align*}
		\{1,2,\ldots,j\}=\sqcup_{k=0}^{m(i_{j},j)-1}\{m\in \mathbb{N}:e^{k+1}(i_{j},j)+1\leq m\leq e^{k}(i_{j},j)\}
	\end{align*}
	Let $k_{0}\in\{0,\ldots,m(i_{j},j)-1\}$ be the unique non negative integer such that \begin{align}\label{eq 1.12}
		e^{k_{0}+1}(i_{j},j)+1\leq l\leq e^{k_{0}}(i_{j},j)
	\end{align}
	Since 	$e^{k_{0}+1}(i_{j},j)+1=d(i_{e^{k_{0}}(i_{j},j)},e^{k_{0}}(i_{j},j))$, from \cref{claim 1}, we have $$\langle\beta_{i_{e^{k_{0}(i_{j},j)}},e^{k_{0}(i_{j},j)}},\lambda_{lq}\rangle=1.$$ Now we prove that $\langle\beta_{i_{e^{k}(i_{j},j)},e^{k}(i_{j},j)},\lambda_{lq}\rangle=0$ for $k\in\{0,\ldots,m(i_{j},j)-1\}\setminus\{k_{0}\}$.
	First assume that $k<k_{0}$. Then by \cref{lemma 2.1}, we have $$e^{k_{0}}(i_{j},j)<e^{k+1}(i_{j},j)+1=d(i_{e^{k}(i_{j},j),e^{k}(i_{j},j)}).$$ Therefore, from \cref{eq 1.12}, we have $l<d(i_{e^{k}(i_{j},j),e^{k}(i_{j},j)})$. Hence, using \cref{claim 1}, we have $\langle\beta_{i_{e^{k}(i_{j},j)},e^{k}(i_{j},j)},\lambda_{lq}\rangle=0$.\\
	Now assume that $k>k_{0}$. Then from \cref{lemma 2.1}, we have $e^{k}(i_{j},j)\leq e^{k_{0}+1}(i_{j},j)$. Therefore from \cref{eq 1.12}, we have $l>e^{k}(i_{j},j)$. Hence from \cref{claim 1}, we have $\langle\beta_{i_{e^{k}(i_{j},j)},e^{k}(i_{j},j)},\lambda_{lq}\rangle=0$. Thus, for $1\leq l\leq j$, we have $$\langle\gamma_{j},\lambda_{lq}\rangle=\langle \beta_{i_{e^{k_{0}}(i_{j},j)},e^{k_{0}}(i_{j},j)},\lambda_{lq}\rangle=1.$$
\end{proof}

