\begin{proof}
(:$\Rightarrow$)	Let $u\in U_{w}$ be such that $x=uwP/P\in X(w)^{ss}_{T_{J_{r}}}(\mathcal{L}(n\omega_{r}))$. Assume on the contrary that, there exists $j\in\{1,2,\ldots,r\}$ such that $X_{\alpha_{i,j}}(u)=0$ for every $i\in\{j,j+1,\ldots,jq\}$ (see \cref{Special eq 2}).\\
	{\it{Case 1}}: $j=r$. Let $w_{1}=(s_{q}\cdots s_{1})\cdots (s_{(r-1)q}\cdots s_{r-1})$. Then $w=w_{1}(s_{rq}\cdots s_{r})$ and $R^{+}(w^{-1})=R^{+}(w_{1}^{-1})\sqcup w_{1}R^{+}((s_{rq}\cdots s_{r})^{-1})$. Therefore, $x\in \prod_{\beta\in R^{+}(w_{1}^{-1})}U_{\beta}wP/P$, by hypothesis. Hence, $w_{1}^{-1}x\in U^{-}(s_{rq}\cdots s_{r})P/P$. Since $w_{1}^{-1}\lambda_{rq}=\lambda_{rq}$, using \cref{variation of Seshadri's lemma}, we have 
	\begin{align}\label{Special eq 5}
		\mu^{\mathcal{L}(n\omega_{r})}(x,-\lambda_{rq})=\langle (s_{rq}\cdots s_{r})(n\omega_{r}),\lambda_{rq}\rangle.
	\end{align}
From \cite[Lemma 5.8]{GKgit}, $X(s_{rq}\cdots s_{r})$, is the unique minimal dimensional Schubert variety in $G/P$ admitting semistable points for $\lambda_{rq}(\mathbb{G}_{m})$-linearized line bundle $\mathcal{L}(n\omega_{r})$. Therefore, from \cite[Lemma 5.4]{GKgit}, we have $\langle (s_{rq}\cdots s_{r})(n\omega_{r}),\lambda_{rq}\rangle<0$. Thus from \cref{Special eq 5} and \cref{HM theorem}, we have that $x\notin X(w)^{ss}_{T_{J_{r}}}(\mathcal{L}(n\omega_{r}))$.

{\it{Case 2}}:  Let $1\leq j\leq r-1$. We prove that there exists a $\lambda\in Y(T_{J_{r}})$ such that $\mu^{\mathcal{L}(n\omega_{r})}(x,\lambda)<0$.\\ Let \begin{align}\label{New proof:1}
	u=\displaystyle\prod_{\substack{l=1\\l\neq j}}^{r}\prod_{i=l}^{lq}u_{\alpha_{i,l}}(a_{i,l}), \text{where $a_{i,l}\in\mathbb{C}$, for all $l\neq j$ and $i=l,\ldots,lq$}.
\end{align}
Following the idea of the proof from \cite[Lemma 5.1]{Ses2}, we find a $\lambda\in Y(T_{J_{r}})$ such that $\lim_{t \to 0} \lambda(t)x=u_{1}wP/P$, where $u_{1}$ centralizes $\lambda$.\\
Let $\lambda=-(n-1)\lambda_{jq}+n\lambda_{(j+1)q}$. 

Let $l\in\{1,2,\ldots,r\}\setminus\{j\}$ and $i\in\{l,l+1,\ldots,lq\}$. Since $l\neq j$, using the description of $\alpha_{i,l}$, we can see that if $\alpha_{jq}\leq \alpha_{i,l}$, then $\alpha_{(j+1)q}\leq \alpha_{i,l}$ and in this case $\langle \alpha_{i,l},\lambda\rangle=1$. If $\alpha_{jq}\nleq\alpha_{i,l}$, then $\langle \alpha_{i,l},\lambda\rangle=n$ or $0$ depending on whether $\alpha_{(j+1)q}\leq \alpha_{i,l}$ or $\alpha_{(j+1)q}\nleq \alpha_{i,l}$ respectively.
Thus for every $l\in\{1,2,\ldots,r\}\setminus\{j\}$ and $i\in\{l,l+1,\ldots,lq\}$, $\langle\alpha_{i,l},\lambda\rangle\in\{0,1,n\}$. Thus, by \cref{New proof:1} we have 
\begin{align*}
	\lim_{t \to 0} \lambda(t)x=\prod_{\substack{\alpha_{i,l}\in R^{+}(w^{-1})\\ \langle\alpha_{i,l},\lambda\rangle=0}}u_{\alpha_{i,l}}(a_{i,l})wP/P.
\end{align*}
Let $u_{1}=\prod_{\substack{\alpha_{i,l}\in R^{+}(w^{-1})\\ \langle\alpha_{i,l},\lambda\rangle=0}}u_{\alpha_{i,l}}(a_{i,l})$. Then $u_{1}$ centralizes $\lambda$. Therefore, using \cite[Proposition 2.1]{Ses2}, we have \begin{align*}
	\mu^{\mathcal{L}(n\omega_{r})}(x,\lambda)&=\mu^{\mathcal{L}(n\omega_{r})}(\lim_{t \to 0} \lambda(t)x,\lambda)
	=	\mu^{\mathcal{L}(n\omega_{r})}(u_{1}wP/P,\lambda).
%	&=\mu^{\mathcal{L}(n\omega_{r})}(wP/P,\lambda)
\end{align*}
Now from \cite[Proposition 3.1]{Ses2}, we have
	\begin{align*}
		\mu^{\mathcal{L}(n\omega_{r})}(u_{1}wP/P,\lambda)
=\mu^{\mathcal{L}(n\omega_{r})}(wP/P,\lambda).
	\end{align*}
Using the similar computation as in \cite[Lemma 5.1]{Ses2}, we can see that the $\lambda(\mathbb{G}_{m})$ acts with weight $-\langle w(n\omega_{r}),\lambda\rangle$ on the fiber of the $T$-fixed point $wP/P$. The sign here is negative because we use the left action of $G$ on $G/B$. Hence from \cite[Definition 2.2]{Ses2}, we have \begin{align*}
	\mu^{\mathcal{L}(n\omega_{r})}(wP/P,\lambda)=-\langle w(n\omega_{r}),\lambda\rangle.
\end{align*}
From \cref{Lemma 4.1}, we can see $-\langle w(n\omega_{r}),\lambda\rangle=-j$. Hence, $\mu^{\mathcal{L}(n\omega_{r})}(wP/P,\lambda)=-j<0$. Now from \cref{HM theorem}, $x$ is not a semistable point.
\end{proof}

